Here is a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:
```
#include <iostream>
#include <fstream>
#include <string>

using namespace std;

int countWords(string filename, string word) {
  int count = 0;
  ifstream file(filename);
  string line;
  while (getline(file, line)) {
    for (char c : line) {
      if (c == word[0]) {
        count++;
      }
    }
  }
  file.close();
  return count;
}

int main() {
  string filename = "text.txt";
  string word = "example";
  int count = countWords(filename, word);
  cout << "The word " << word << " appears " << count << " times in the file." << endl;
  return 0;
}
```
In this program, we use the `fstream` library to open the file specified by `filename` and the `getline` function to read each line of the file using a `string`. We then loop through each character in the line using a `for` loop and check if it matches the first character of the `word` string. If it does, we increment the `count` variable. Finally, we close the file and return the count.

