#include <string>
#include <vector>
#include <unordered_map>

using namespace std;

int countWords(string filename, string word) {
  int count = 0;
  ifstream file(filename);
  string line;
  while (getline(file, line)) {
    unordered_map<char, vector<string>> wordMap;
    for (char c : line) {
      if (c == word[0]) {
        wordMap[c].push_back(line);
      }
    }
    for (char c : word) {
      if (wordMap.find(c)!= wordMap.end()) {
        count += wordMap[c].size();
      }
    }
  }
  file.close();
  return count;
}

int main() {
  string filename = "text.txt";
  string word = "example";
  int count = countWords(filename, word);
  cout << "The word " << word << " appears " << count << " times in the file." << endl;
  return 0;
}
```
